 10→pub type CommentsMap = FxHashMap</* attached_to */ u32, Vec<Comment>>;
 11→
 12→impl Codegen<'_> {
 13→    pub(crate) fn build_comments(&mut self, comments: &[Comment]) {
 14→        if self.options.comments == CommentOptions::disabled() {
 15→            return;
 16→        }
 17→        for comment in comments {
 18→            // Omit pure comments because they are handled separately.
 19→            if comment.is_pure() || comment.is_no_side_effects() {
 20→                continue;
 21→            }
 22→            let mut add = false;
 23→            if comment.is_leading() {
 24→                if comment.is_legal() && self.options.print_legal_comment() {
 25→                    add = true;
 26→                }
 27→                if comment.is_jsdoc() && self.options.print_jsdoc_comment() {
 28→                    add = true;
 29→                }
 30→                if comment.is_annotation() && self.options.print_annotation_comment() {
 31→                    add = true;
 32→                }
 33→                if comment.is_normal() && self.options.print_normal_comment() {
 34→                    add = true;
 35→                }
 36→            }
 37→            if add {
 38→                self.comments.entry(comment.attached_to).or_default().push(*comment);
 39→            }
 40→        }
 41→    }
 42→
 43→    pub(crate) fn has_comment(&self, start: u32) -> bool {
 44→        self.comments.contains_key(&start)
 45→    }
 46→
 47→    pub(crate) fn print_leading_comments(&mut self, start: u32) {
 48→        if let Some(comments) = self.comments.remove(&start) {
 49→            self.print_comments(&comments);
 50→        }
 51→    }
 52→
 53→    pub(crate) fn get_comments(&mut self, start: u32) -> Option<Vec<Comment>> {
 54→        if self.comments.is_empty() {
 55→            return None;
 56→        }
 57→        self.comments.remove(&start)
 58→    }
 59→
 60→    #[inline]
 61→    pub(crate) fn print_comments_at(&mut self, start: u32) {
 62→        if let Some(comments) = self.get_comments(start) {
 63→            self.print_comments(&comments);
 64→        }
 65→    }
 66→
 67→    /// Print comments attached to any position in the given range `(start, end)` (exclusive).
 68→    /// Returns `true` if any comments were printed.
 69→    pub(crate) fn print_comments_in_range(&mut self, start: u32, end: u32) -> bool {
 70→        if self.comments.is_empty() {
 71→            return false;
 72→        }
 73→        // Find and remove the first key in the range.
 74→        let key = self.comments.keys().find(|&&k| k > start && k < end).copied();
 75→        if let Some(key) = key {
 76→            let comments = self.comments.remove(&key).unwrap();
 77→            self.print_comments(&comments);
 78→            return true;
 79→        }
 80→        false
 81→    }
 82→
 83→    pub(crate) fn print_expr_comments(&mut self, start: u32) -> bool {
 84→        if self.comments.is_empty() {
 85→            return false;
 86→        }
 87→        let Some(comments) = self.comments.remove(&start) else { return false };
 88→
 89→        for comment in &comments {
 90→            self.print_hard_newline();
 91→            self.print_indent();
 92→            self.print_comment(comment);
 93→        }
 94→
 95→        if comments.is_empty() {
 96→            false
 97→        } else {
 98→            self.print_hard_newline();
 99→            true
100→        }
101→    }
102→
103→    pub(crate) fn print_comments(&mut self, comments: &[Comment]) {
104→        let Some((first, rest)) = comments.split_first() else {
105→            return;
106→        };
107→
108→        if first.preceded_by_newline() {
109→            // Skip printing newline if this comment is already on a newline.
110→            if let Some(b) = self.last_byte() {
111→                match b {
112→                    b'\n' => self.print_indent(),
113→                    b'\t' => { /* noop */ }
114→                    _ => {
115→                        self.print_hard_newline();
116→                        self.print_indent();
117→                    }
118→                }
119→            }
120→        } else {
121→            self.print_indent();
122→        }
123→        self.print_comment(first);
124→
125→        if let Some((last, middle)) = rest.split_last() {
126→            for comment in middle {
127→                if comment.preceded_by_newline() {
128→                    self.print_hard_newline();
129→                    self.print_indent();
130→                } else if comment.is_legal() {
131→                    self.print_hard_newline();
132→                } else {
133→                    self.print_soft_space();
134→                }
135→                self.print_comment(comment);
136→            }
137→
138→            if last.preceded_by_newline() {
139→                self.print_hard_newline();
140→                self.print_indent();
141→            } else if last.is_legal() {
142→                self.print_hard_newline();
143→            } else {
144→                self.print_soft_space();
145→            }
146→            self.print_comment(last);
147→
148→            if last.is_line() || last.followed_by_newline() {
149→                self.print_hard_newline();
150→            } else {
151→                self.print_next_indent_as_space = true;
152→            }
153→        } else if first.is_line() || first.followed_by_newline() {
154→            self.print_hard_newline();
155→        } else {
156→            self.print_next_indent_as_space = true;
157→        }
158→    }
159→
160→    fn print_comment(&mut self, comment: &Comment) {
161→        let Some(source_text) = self.source_text else {
162→            return;
163→        };
164→        let comment_source = comment.span.source_text(source_text);
165→        match comment.kind {
166→            CommentKind::Line | CommentKind::SingleLineBlock => {
167→                self.print_str_escaping_script_close_tag(comment_source);
168→            }
169→            CommentKind::MultiLineBlock => {
170→                for line in LineTerminatorSplitter::new(comment_source) {
171→                    if !line.starts_with("/*") {
172→                        self.print_indent();
173→                    }
174→                    self.print_str_escaping_script_close_tag(line.trim_start());
175→                    if !line.ends_with("*/") {
176→                        self.print_hard_newline();
177→                    }
178→                }
179→            }
180→        }
181→    }
182→
183→    /// Handle Eof / Linked / External Comments.
184→    /// Return a list of comments of linked or external.
185→    pub(crate) fn handle_eof_linked_or_external_comments(
186→        &mut self,
187→        program: &Program<'_>,
188→    ) -> Vec<Comment> {
189→        let legal_comments = &self.options.comments.legal;
190→        if matches!(legal_comments, LegalComment::None | LegalComment::Inline) {
191→            return vec![];
192→        }
193→
194→        // Dedupe legal comments for smaller output size.
195→        let mut set = FxHashSet::default();
196→        let mut comments = vec![];
197→
198→        let source_text = program.source_text;
199→        for comment in program.comments.iter().filter(|c| c.is_legal()) {
200→            let mut text = Cow::Borrowed(comment.span.source_text(source_text));
201→            if comment.is_multiline_block() {
202→                let mut buffer = String::with_capacity(text.len());
203→                // Print block comments with our own indentation.
204→                for line in LineTerminatorSplitter::new(&text) {
205→                    if !line.starts_with("/*") {
206→                        buffer.push('\t');
207→                    }
208→                    buffer.push_str(line.trim_start());
209→                    if !line.ends_with("*/") {
210→                        buffer.push('\n');
211→                    }
212→                }
213→                text = Cow::Owned(buffer);
214→            }
215→            if set.insert(text) {
216→                comments.push(*comment);
217→            }
218→        }
219→
220→        if comments.is_empty() {
221→            return vec![];
222→        }
223→
224→        match legal_comments {
225→            LegalComment::Eof => {
226→                self.print_hard_newline();
227→                // Clear the flag to ensure consistent formatting for all EOF comments
228→                self.print_next_indent_as_space = false;
229→                for c in comments {
230→                    self.print_comment(&c);
231→                    self.print_hard_newline();
232→                }
233→                vec![]
234→            }
235→            LegalComment::Linked(path) => {
236→                let path = path.clone();
237→                self.print_hard_newline();
238→                self.print_str("/*! For license information please see ");
239→                self.print_str(&path);
240→                self.print_str(" */");
241→                comments
242→            }
243→            LegalComment::External => comments,
244→            LegalComment::None | LegalComment::Inline => unreachable!(),
245→        }
246→    }
247→}
