  3→#[test]
  4→fn test_comment_at_top_of_file() {
  5→    use oxc_allocator::Allocator;
  6→    use oxc_ast::CommentPosition;
  7→    use oxc_codegen::Codegen;
  8→    use oxc_parser::Parser;
  9→    use oxc_span::SourceType;
 10→    let source_type = SourceType::mjs();
 11→    let allocator = Allocator::default();
 12→    let mut ret = Parser::new(&allocator, "export{} /** comment */", source_type).parse();
 13→    // Move comment to top of the file.
 14→    ret.program.comments[0].attached_to = 0;
 15→    ret.program.comments[0].position = CommentPosition::Leading;
 16→    let code = Codegen::new().build(&ret.program).code;
 17→    assert_eq!(code, "/** comment */ export {};\n");
 18→}
 19→
 20→#[test]
 21→fn unit() {
 22→    test_same("<div>{/* Hello */}</div>;\n");
 23→    // https://github.com/oxc-project/oxc/issues/17266
 24→    test("console.log(<div x={/*before*/ x} />)", "console.log(<div x={/*before*/ x} />);\n");
 25→    test(
 26→        "console.log(<div x={/*before*/ \"y\"} />)",
 27→        "console.log(<div x={/*before*/ \"y\"} />);\n",
 28→    );
 29→    test("console.log(<div x={/*before*/ true} />)", "console.log(<div x={/*before*/ true} />);\n");
 30→    test("console.log(<div {/*before*/ ...x} />)", "console.log(<div {/*before*/ ...x} />);\n");
 31→    test("console.log(<div>{/*before*/ x}</div>)", "console.log(<div>{/*before*/ x}</div>);\n");
 32→    test("console.log(<>{/*before*/ x}</>)", "console.log(<>{/*before*/ x}</>);\n");
 33→    // https://lingui.dev/ref/macro#definemessage
 34→    test("const message = /*i18n*/{};", "const message = (/*i18n*/ {});\n");
 35→    test(
 36→        "function foo() { return /*i18n*/ {} }",
 37→        "function foo() {\n\treturn (\t/*i18n*/ {});\n}\n",
 38→    );
 39→
 40→    test_same("export { /** @deprecated */ parseAst } from \"rolldown/parseAst\";\n");
 41→    test_same("export { /** @deprecated */ parseAst };\n");
 42→    test_same("export { parseAst as /** @deprecated */ b } from \"rolldown/parseAst\";\n");
 43→    test_same("export { parseAst as /** @deprecated */ b };\n");
 44→}
