  1→use memchr::memchr_iter;
  2→use oxc_ast::ast::{Comment, CommentContent, CommentKind, CommentPosition};
  3→use oxc_span::Span;
  4→
  5→use super::{Kind, Token};
  6→
  7→#[derive(Debug)]
  8→pub struct TriviaBuilder {
  9→    // This is a set of unique comments. Duplicated
 10→    // comments could be generated in case of rewind; they are
 11→    // filtered out at insertion time.
 12→    pub(crate) comments: Vec<Comment>,
 13→
 14→    pub(crate) irregular_whitespaces: Vec<Span>,
 15→
 16→    // states
 17→    /// index of processed comments
 18→    processed: usize,
 19→
 20→    /// Saw a newline before this position (since last token).
 21→    /// Used to determine if comments are trailing comments of the previous token.
 22→    saw_newline: bool,
 23→
 24→    /// Saw a newline before this position (since last comment or token).
 25→    /// Used to set `preceded_by_newline` on comments.
 26→    saw_newline_for_comment: bool,
 27→
 28→    /// Previous token kind, used to indicates comments are trailing from what kind
 29→    previous_kind: Kind,
 30→
 31→    pub(super) has_pure_comment: bool,
 32→
 33→    pub(super) has_no_side_effects_comment: bool,
 34→}
 35→
 36→impl Default for TriviaBuilder {
 37→    fn default() -> Self {
 38→        Self {
 39→            comments: vec![],
 40→            irregular_whitespaces: vec![],
 41→            processed: 0,
 42→            saw_newline: true,
 43→            saw_newline_for_comment: true,
 44→            previous_kind: Kind::Undetermined,
 45→            has_pure_comment: false,
 46→            has_no_side_effects_comment: false,
 47→        }
 48→    }
 49→}
 50→
 51→impl TriviaBuilder {
 52→    pub fn previous_token_has_pure_comment(&self) -> bool {
 53→        self.has_pure_comment
 54→    }
 55→
 56→    pub fn previous_token_has_no_side_effects_comment(&self) -> bool {
 57→        self.has_no_side_effects_comment
 58→    }
 59→
 60→    pub fn add_irregular_whitespace(&mut self, start: u32, end: u32) {
 61→        self.irregular_whitespaces.push(Span::new(start, end));
 62→    }
 63→
 64→    pub fn add_line_comment(&mut self, start: u32, end: u32, source_text: &str) {
 65→        self.add_comment(Comment::new(start, end, CommentKind::Line), source_text);
 66→    }
 67→
 68→    pub fn add_block_comment(
 69→        &mut self,
 70→        start: u32,
 71→        end: u32,
 72→        kind: CommentKind,
 73→        source_text: &str,
 74→    ) {
 75→        self.add_comment(Comment::new(start, end, kind), source_text);
 76→    }
 77→
 78→    // For block comments only. This function is not called after line comments because the lexer skips
 79→    // newline after line comments.
 80→    pub fn handle_newline(&mut self) {
 81→        // The last unprocessed comment is on a newline.
 82→        let len = self.comments.len();
 83→        if self.processed < len {
 84→            self.comments[len - 1].set_followed_by_newline(true);
 85→            if !self.saw_newline {
 86→                self.processed = self.comments.len();
 87→            }
 88→        }
 89→        self.saw_newline = true;
 90→        self.saw_newline_for_comment = true;
 91→    }
 92→
 93→    pub fn handle_token(&mut self, token: Token) {
 94→        let len = self.comments.len();
 95→        self.previous_kind = token.kind();
 96→        if self.processed < len {
 97→            // All unprocessed preceding comments are leading comments attached to this token start.
 98→            for comment in &mut self.comments[self.processed..] {
 99→                comment.position = CommentPosition::Leading;
100→                comment.attached_to = token.start();
101→            }
102→            self.processed = len;
103→        }
104→        self.saw_newline = false;
105→        self.saw_newline_for_comment = false;
106→    }
107→
108→    /// Determines if the current line comment should be treated as a trailing comment.
109→    ///
110→    /// A line comment should be treated as trailing when both of the following conditions are met:
111→    ///
112→    /// 1. It is not preceded by a newline.
113→    ///
114→    /// ```javascript
115→    /// let x = 5; // This should be treated as a trailing comment
116→    /// foo(); // This should also be treated as a trailing comment
117→    ///
118→    /// // This should not be treated as trailing (preceded by newline)
119→    /// let x = 5;
120→    /// ```
121→    ///
122→    /// 2. It does not immediately follow an `=` [`Kind::Eq`] or `(` [`Kind::LParen`]
123→    ///    token.
124→    ///
125→    /// ```javascript
126→    /// let y = // This should not be treated as trailing (follows `=`)
127→    ///     10;
128→    ///
129→    /// function foo( // This should not be treated as trailing (follows `(`)
130→    ///     param
131→    /// ) {}
132→    /// ```
133→    fn should_be_treated_as_trailing_comment(&self) -> bool {
134→        !self.saw_newline && !matches!(self.previous_kind, Kind::Eq | Kind::LParen)
135→    }
136→
137→    fn add_comment(&mut self, mut comment: Comment, source_text: &str) {
138→        self.parse_annotation(&mut comment, source_text);
139→        // The comments array is an ordered vec, only add the comment if its not added before,
140→        // to avoid situations where the parser needs to rewind and tries to reinsert the comment.
141→        if let Some(last_comment) = self.comments.last()
142→            && comment.span.start <= last_comment.span.start
143→        {
144→            return;
145→        }
146→
147→        // This newly added comment may be preceded by a newline.
148→        // Use `saw_newline_for_comment` which tracks newlines since the last comment or token,
149→        // not just since the last token.
150→        comment.set_preceded_by_newline(self.saw_newline_for_comment);
151→        if comment.is_line() {
152→            // A line comment is always followed by a newline. This is never set in `handle_newline`.
153→            comment.set_followed_by_newline(true);
154→            if self.should_be_treated_as_trailing_comment() {
155→                self.processed = self.comments.len() + 1; // +1 to include this comment.
156→            }
157→            self.saw_newline = true;
158→            self.saw_newline_for_comment = true;
159→        } else {
160→            // Block comments don't end with a newline, so reset saw_newline_for_comment.
161→            // If there's a newline after the block comment, `handle_newline` will set it back to true.
162→            self.saw_newline_for_comment = false;
163→        }
164→
165→        self.comments.push(comment);
166→    }
167→
168→    /// Parse Notation
169→    fn parse_annotation(&mut self, comment: &mut Comment, source_text: &str) {
170→        let s = comment.content_span().source_text(source_text);
171→        let bytes = s.as_bytes();
172→
173→        // Early exit for empty comments
174→        if bytes.is_empty() {
175→            return;
176→        }
177→
178→        // Check first byte for quick routing
179→        match bytes[0] {
180→            b'!' => {
181→                comment.content = CommentContent::Legal;
182→                return;
183→            }
184→            b'*' if comment.is_block() => {
185→                // Ignore webpack comment `/*****/`
186→                if !bytes.iter().all(|&c| c == b'*') {
187→                    if contains_license_or_preserve_comment(s) {
188→                        comment.content = CommentContent::JsdocLegal;
189→                    } else {
190→                        comment.content = CommentContent::Jsdoc;
191→                    }
192→                }
193→                return;
194→            }
195→            _ => {}
196→        }
197→
198→        // Skip leading whitespace without allocation
199→        let mut start = 0;
200→        while start < bytes.len() && bytes[start].is_ascii_whitespace() {
201→            start += 1;
202→        }
203→
204→        if start >= bytes.len() {
205→            return;
206→        }
207→
208→        // Fast path: check first non-whitespace byte
209→        match bytes[start] {
210→            b'@' => {
211→                start += 1;
212→                if start >= bytes.len() {
213→                    return;
214→                }
215→
216→                // Check for @vite, @license, @preserve
217→                if bytes[start..].starts_with(b"vite") {
218→                    comment.content = CommentContent::Vite;
219→                    return;
220→                }
221→                if bytes[start..].starts_with(b"license") || bytes[start..].starts_with(b"preserve")
222→                {
223→                    comment.content = CommentContent::Legal;
224→                    return;
225→                }
226→
227→                // Continue to check for __PURE__ or __NO_SIDE_EFFECTS__ after @
228→            }
229→            b'#' => {
230→                start += 1;
231→                // Continue to check for __PURE__ or __NO_SIDE_EFFECTS__ after #
232→            }
233→            b'w' => {
234→                // Check for webpack comments
235→                if bytes[start..].starts_with(b"webpack")
236→                    && start + 7 < bytes.len()
237→                    && bytes[start + 7].is_ascii_uppercase()
238→                {
239→                    comment.content = CommentContent::Webpack;
240→                    return;
241→                }
242→                // Fall through to check for coverage ignore patterns
243→            }
244→            b'v' | b'c' | b'n' | b'i' => {
245→                // Check coverage ignore patterns: "v8 ignore", "c8 ignore", "node:coverage", "istanbul ignore"
246→                let rest = &bytes[start..];
247→                if rest.starts_with(b"v8 ignore")
248→                    || rest.starts_with(b"c8 ignore")
249→                    || rest.starts_with(b"node:coverage")
250→                    || rest.starts_with(b"istanbul ignore")
251→                {
252→                    comment.content = CommentContent::CoverageIgnore;
253→                    return;
254→                }
255→                // Fall through to check license/preserve
256→            }
257→            _ => {
258→                // Check for license/preserve comments in remaining cases
259→                if contains_license_or_preserve_comment(s) {
260→                    comment.content = CommentContent::Legal;
261→                }
262→                return;
263→            }
264→        }
265→
266→        // Check for __PURE__ or __NO_SIDE_EFFECTS__ after @ or #
267→        if start < bytes.len() && bytes[start..].starts_with(b"__") {
268→            let rest = &bytes[start + 2..];
269→            if rest.starts_with(b"PURE__") {
270→                comment.content = CommentContent::Pure;
271→                self.has_pure_comment = true;
272→                return;
273→            } else if rest.starts_with(b"NO_SIDE_EFFECTS__") {
274→                comment.content = CommentContent::NoSideEffects;
275→                self.has_no_side_effects_comment = true;
276→                return;
277→            }
278→        }
279→
280→        // Fallback: check for @license or @preserve anywhere in the comment
281→        // This handles cases like /* @foo @preserve */ where the first @ doesn't match known patterns
282→        if contains_license_or_preserve_comment(s) {
283→            comment.content = CommentContent::Legal;
284→        }
285→    }
286→}
