288→#[expect(clippy::inline_always)]
289→#[inline(always)]
290→fn contains_license_or_preserve_comment(s: &str) -> bool {
291→    let hay = s.as_bytes();
292→
293→    if hay.len() < 9 {
294→        return false;
295→    }
296→
297→    let search_len = hay.len() - 8;
298→
299→    for i in memchr_iter(b'@', &hay[..search_len]) {
300→        debug_assert!(i < search_len);
301→        // SAFETY: we `i` has a max val of len of bytes - 8, so accessing `i + 1` is safe
302→        match unsafe { hay.get_unchecked(i + 1) } {
303→            // spellchecker:off
304→            b'l' => {
305→                // SAFETY: we `i` has a max val of len of bytes - 8, so accessing `i + 7` is safe
306→                if unsafe { hay.get_unchecked(i + 2..i + 1 + 7) } == b"icense" {
307→                    return true;
308→                }
309→            }
310→            b'p' => {
311→                // SAFETY: we `i` has a max val of len of bytes - 8, so accessing `i + 8` is safe
312→                if unsafe { hay.get_unchecked(i + 2..i + 1 + 8) } == b"reserve" {
313→                    return true;
314→                }
315→            }
316→            // spellchecker:on
317→            _ => {}
318→        }
319→    }
320→
321→    false
322→}
