input.old_string:
if comment.is_line() {
    // A line comment is always followed by a newline. This is never set in `handle_newline`.
    comment.set_followed_by_newline(true);
    if self.should_be_treated_as_trailing_comment() {
        self.processed = self.comments.len() + 1; // +1 to include this comment.
    }

input.new_string:
if comment.is_line() {
    // A line comment is always followed by a newline. This is never set in `handle_newline`.
    comment.set_followed_by_newline(true);
    // Legal comments (e.g. `//!`, `@license`, `@preserve`) should not be treated as
    // trailing comments. They need to remain unprocessed so the next `handle_token` call
    // converts them to leading comments and attaches them to the next token.
    // This ensures trailing legal comments like `foo() //! license` are preserved in codegen.
    // See: https://github.com/oxc-project/oxc/issues/17301
