// For block comments only. This function is not called after line comments because the lexer skips
// newline after line comments.
pub fn handle_newline(&mut self) {
    // The last unprocessed comment is on a newline.
    let len = self.comments.len();
    if self.processed < len {
        self.comments[len - 1].set_followed_by_newline(true);
        if !self.saw_newline {
            // Don't treat legal block comments as trailing.
            // They should remain unprocessed so they become leading comments of the next token.
            // See: https://github.com/oxc-project/oxc/issues/17301
            let has_legal = self.comments[self.processed..].iter().any(|c| {
                matches!(c.content, CommentContent::Legal | CommentContent::JsdocLegal)
            });
            if !has_legal {
                self.processed = self.comments.len();
            }
        }
    }
    self.saw_newline = true;
    self.saw_newline_for_comment = true;
}

