 10→    // comments could be generated in case of rewind; they are
 11→    // filtered out at insertion time.
 12→    pub(crate) comments: Vec<Comment>,
 13→
 14→    pub(crate) irregular_whitespaces: Vec<Span>,
 15→
 16→    // states
 17→    /// index of processed comments
 18→    processed: usize,
 19→
 20→    /// Saw a newline before this position (since last token).
 21→    /// Used to determine if comments are trailing comments of the previous token.
 22→    saw_newline: bool,
 23→
 24→    /// Saw a newline before this position (since last comment or token).
 25→    /// Used to set `preceded_by_newline` on comments.
 26→    saw_newline_for_comment: bool,
 27→
 28→    /// Previous token kind, used to indicates comments are trailing from what kind
 29→    previous_kind: Kind,
 30→
 31→    pub(super) has_pure_comment: bool,
 32→
 33→    pub(super) has_no_side_effects_comment: bool,
 34→}
 35→
 36→impl Default for TriviaBuilder {
 37→    fn default() -> Self {
 38→        Self {
 39→            comments: vec![],
 40→            irregular_whitespaces: vec![],
 41→            processed: 0,
 42→            saw_newline: true,
 43→            saw_newline_for_comment: true,
 44→            previous_kind: Kind::Undetermined,
 45→            has_pure_comment: false,
 46→            has_no_side_effects_comment: false,
 47→        }
 48→    }
 49→}
 50→
 51→impl TriviaBuilder {
 52→    pub fn previous_token_has_pure_comment(&self) -> bool {
 53→        self.has_pure_comment
 54→    }
 55→
 56→    pub fn previous_token_has_no_side_effects_comment(&self) -> bool {
 57→        self.has_no_side_effects_comment
 58→    }
 59→
 60→    pub fn add_irregular_whitespace(&mut self, start: u32, end: u32) {
 61→        self.irregular_whitespaces.push(Span::new(start, end));
 62→    }
 63→
 64→    pub fn add_line_comment(&mut self, start: u32, end: u32, source_text: &str) {
 65→        self.add_comment(Comment::new(start, end, CommentKind::Line), source_text);
 66→    }
 67→
 68→    pub fn add_block_comment(
 69→        &mut self,
 70→        start: u32,
 71→        end: u32,
 72→        kind: CommentKind,
 73→        source_text: &str,
 74→    ) {
 75→        self.add_comment(Comment::new(start, end, kind), source_text);
 76→    }
 77→
 78→    // For block comments only. This function is not called after line comments because the lexer skips
 79→    // newline after line comments.
 80→    pub fn handle_newline(&mut self) {
 81→        // The last unprocessed comment is on a newline.
 82→        let len = self.comments.len();
 83→        if self.processed < len {
 84→            self.comments[len - 1].set_followed_by_newline(true);
 85→            if !self.saw_newline {
 86→                // Don't treat legal block comments as trailing.
 87→                // They should remain unprocessed so they become leading comments of the next token.
 88→                // See: https://github.com/oxc-project/oxc/issues/17301
 89→                let has_legal = self.comments[self.processed..].iter().any(|c| {
 90→                    matches!(c.content, CommentContent::Legal | CommentContent::JsdocLegal)
 91→                });
 92→                if !has_legal {
 93→                    self.processed = self.comments.len();
 94→                }
 95→            }
 96→        }
 97→        self.saw_newline = true;
 98→        self.saw_newline_for_comment = true;
 99→    }
100→
101→    pub fn handle_token(&mut self, token: Token) {
102→        let len = self.comments.len();
103→        self.previous_kind = token.kind();
104→        if self.processed < len {
105→            // All unprocessed preceding comments are leading comments attached to this token start.
106→            for comment in &mut self.comments[self.processed..] {
107→                comment.position = CommentPosition::Leading;
108→                comment.attached_to = token.start();
109→            }
110→            self.processed = len;
111→        }
112→        self.saw_newline = false;
113→        self.saw_newline_for_comment = false;
114→    }
115→
116→    /// Determines if the current line comment should be treated as a trailing comment.
117→    ///
118→    /// A line comment should be treated as trailing when both of the following conditions are met:
119→    ///
120→    /// 1. It is not preceded by a newline.
121→    ///
122→    /// ```javascript
123→    /// let x = 5; // This should be treated as a trailing comment
124→    /// foo(); // This should also be treated as a trailing comment
125→    ///
126→    /// // This should not be treated as trailing (preceded by newline)
127→    /// let x = 5;
128→    /// ```
129→    ///
130→    /// 2. It does not immediately follow an `=` [`Kind::Eq`] or `(` [`Kind::LParen`]
131→    ///    token.
132→    ///
133→    /// ```javascript
134→    /// let y = // This should not be treated as trailing (follows `=`)
135→    ///     10;
136→    ///
137→    /// function foo( // This should not be treated as trailing (follows `(`)
138→    ///     param
139→    /// ) {}
140→    /// ```
141→    fn should_be_treated_as_trailing_comment(&self) -> bool {
142→        !self.saw_newline && !matches!(self.previous_kind, Kind::Eq | Kind::LParen)
143→    }
144→
145→    fn add_comment(&mut self, mut comment: Comment, source_text: &str) {
146→        self.parse_annotation(&mut comment, source_text);
147→        // The comments array is an ordered vec, only add the comment if its not added before,
148→        // to avoid situations where the parser needs to rewind and tries to reinsert the comment.
149→        if let Some(last_comment) = self.comments.last()
150→            && comment.span.start <= last_comment.span.start
151→        {
152→            return;
153→        }
154→
155→        // This newly added comment may be preceded by a newline.
156→        // Use `saw_newline_for_comment` which tracks newlines since the last comment or token,
157→        // not just since the last token.
158→        comment.set_preceded_by_newline(self.saw_newline_for_comment);
159→        if comment.is_line() {
160→            // A line comment is always followed by a newline. This is never set in `handle_newline`.
161→            comment.set_followed_by_newline(true);
162→            // Legal comments (e.g. `//!`, `@license`, `@preserve`) should not be treated as
163→            // trailing comments. They need to remain unprocessed so the next `handle_token` call
164→            // converts them to leading comments and attaches them to the next token.
165→            // This ensures trailing legal comments like `foo() //! license` are preserved in codegen.
166→            // See: https://github.com/oxc-project/oxc/issues/17301
167→            if self.should_be_treated_as_trailing_comment()
168→                && !matches!(
169→                    comment.content,
170→                    CommentContent::Legal | CommentContent::JsdocLegal
171→                )
172→            {
173→                self.processed = self.comments.len() + 1; // +1 to include this comment.
174→            }
175→            self.saw_newline = true;
176→            self.saw_newline_for_comment = true;
177→        } else {
178→            // Block comments don't end with a newline, so reset saw_newline_for_comment.
179→            // If there's a newline after the block comment, `handle_newline` will set it back to true.
180→            self.saw_newline_for_comment = false;
181→        }
182→
183→        self.comments.push(comment);
184→    }
185→
186→    /// Parse Notation
187→    fn parse_annotation(&mut self, comment: &mut Comment, source_text: &str) {
188→        let s = comment.content_span().source_text(source_text);
189→        let bytes = s.as_bytes();
190→
191→        // Early exit for empty comments
192→        if bytes.is_empty() {
193→            return;
194→        }
195→
196→        // Check first byte for quick routing
197→        match bytes[0] {
198→            b'!' => {
199→                comment.content = CommentContent::Legal;
200→                return;
201→            }
202→            b'*' if comment.is_block() => {
203→                // Ignore webpack comment `/*****/`
204→                if !bytes.iter().all(|&c| c == b'*') {
205→                    if contains_license_or_preserve_comment(s) {
206→                        comment.content = CommentContent::JsdocLegal;
207→                    } else {
208→                        comment.content = CommentContent::Jsdoc;
209→                    }
210→                }
211→                return;
212→            }
213→            _ => {}
214→        }
215→
216→        // Skip leading whitespace without allocation
217→        let mut start = 0;
218→        while start < bytes.len() && bytes[start].is_ascii_whitespace() {
219→            start += 1;
220→        }
221→
222→        if start >= bytes.len() {
223→            return;
224→        }
225→
226→        // Fast path: check first non-whitespace byte
227→        match bytes[start] {
228→            b'@' => {
229→                start += 1;
230→                if start >= bytes.len() {
231→                    return;
232→                }
233→
234→                // Check for @vite, @license, @preserve
235→                if bytes[start..].starts_with(b"vite") {
236→                    comment.content = CommentContent::Vite;
237→                    return;
238→                }
239→                if bytes[start..].starts_with(b"license") || bytes[start..].starts_with(b"preserve")
240→                {
241→                    comment.content = CommentContent::Legal;
242→                    return;
243→                }
244→
245→                // Continue to check for __PURE__ or __NO_SIDE_EFFECTS__ after @
246→            }
247→            b'#' => {
248→                start += 1;
249→                // Continue to check for __PURE__ or __NO_SIDE_EFFECTS__ after #
250→            }
251→            b'w' => {
252→                // Check for webpack comments
253→                if bytes[start..].starts_with(b"webpack")
254→                    && start + 7 < bytes.len()
255→                    && bytes[start + 7].is_ascii_uppercase()
256→                {
257→                    comment.content = CommentContent::Webpack;
258→                    return;
259→                }
260→                // Fall through to check for coverage ignore patterns
261→            }
262→            b'v' | b'c' | b'n' | b'i' => {
263→                // Check coverage ignore patterns: "v8 ignore", "c8 ignore", "node:coverage", "istanbul ignore"
264→                let rest = &bytes[start..];
265→                if rest.starts_with(b"v8 ignore")
266→                    || rest.starts_with(b"c8 ignore")
267→                    || rest.starts_with(b"node:coverage")
268→                    || rest.starts_with(b"istanbul ignore")
269→                {
270→                    comment.content = CommentContent::CoverageIgnore;
271→                    return;
272→                }
273→                // Fall through to check license/preserve
274→            }
275→            _ => {
276→                // Check for license/preserve comments in remaining cases
277→                if contains_license_or_preserve_comment(s) {
278→                    comment.content = CommentContent::Legal;
279→                }
280→                return;
281→            }
282→        }
283→
284→        // Check for __PURE__ or __NO_SIDE_EFFECTS__ after @ or #
285→        if start < bytes.len() && bytes[start..].starts_with(b"__") {
286→            let rest = &bytes[start + 2..];
287→            if rest.starts_with(b"PURE__") {
288→                comment.content = CommentContent::Pure;
289→                self.has_pure_comment = true;
290→                return;
291→            } else if rest.starts_with(b"NO_SIDE_EFFECTS__") {
292→                comment.content = CommentContent::NoSideEffects;
293→                self.has_no_side_effects_comment = true;
294→                return;
295→            }
296→        }
297→
298→        // Fallback: check for @license or @preserve anywhere in the comment
299→        // This handles cases like /* @foo @preserve */ where the first @ doesn't match known patterns
300→        if contains_license_or_preserve_comment(s) {
301→            comment.content = CommentContent::Legal;
302→        }
303→    }
304→}
305→
306→#[expect(clippy::inline_always)]
307→#[inline(always)]
308→fn contains_license_or_preserve_comment(s: &str) -> bool {
309→    let hay = s.as_bytes();
310→
311→    if hay.len() < 9 {
312→        return false;
313→    }
314→
315→    let search_len = hay.len() - 8;
316→
317→    for i in memchr_iter(b'@', &hay[..search_len]) {
318→        debug_assert!(i < search_len);
319→        // SAFETY: we `i` has a max val of len of bytes - 8, so accessing `i + 1` is safe
320→        match unsafe { hay.get_unchecked(i + 1) } {
321→            // spellchecker:off
322→            b'l' => {
323→                // SAFETY: we `i` has a max val of len of bytes - 8, so accessing `i + 7` is safe
324→                if unsafe { hay.get_unchecked(i + 2..i + 1 + 7) } == b"icense" {
325→                    return true;
326→                }
327→            }
328→            b'p' => {
329→                // SAFETY: we `i` has a max val of len of bytes - 8, so accessing `i + 8` is safe
330→                if unsafe { hay.get_unchecked(i + 2..i + 1 + 8) } == b"reserve" {
331→                    return true;
332→                }
333→            }
334→            // spellchecker:on
335→            _ => {}
336→        }
337→    }
338→
339→    false
340→}
