pub(crate) fn build_comments(&mut self, comments: &[Comment], program_end: u32) {
    if self.options.comments == CommentOptions::disabled() {
        return;
    }

    // Trailing legal comments (e.g. `foo() //! license`) have `attached_to: 0` because
    // the parser doesn't attach trailing comments to tokens. We need to re-attach them
    // to the next token so they appear in the output.
    // Collect pending trailing legal comments and flush them when we find the next leading comment.
    // See: <https://github.com/oxc-project/oxc/issues/17301>
    let mut pending_trailing_legal: Vec<Comment> = vec![];

    for comment in comments {
        // Omit pure comments because they are handled separately.
        if comment.is_pure() || comment.is_no_side_effects() {
            continue;
        }

        // Flush pending trailing legal comments when we encounter a leading comment,
        // attaching them to the same token as this leading comment.
        if comment.is_leading() && !pending_trailing_legal.is_empty() {
            let attached_to = comment.attached_to;
            for mut tc in pending_trailing_legal.drain(..) {
                tc.attached_to = attached_to;
                self.comments.entry(attached_to).or_default().push(tc);
            }
        }

        let mut add = false;
        if comment.is_leading() {
            if comment.is_legal() && self.options.print_legal_comment() {
                add = true;
            }
            if comment.is_jsdoc() && self.options.print_jsdoc_comment() {
                add = true;
            }
            if comment.is_annotation() && self.options.print_annotation_comment() {
                add = true;
            }
            if comment.is_normal() && self.options.print_normal_comment() {
                add = true;
            }
        } else if comment.is_trailing()
            && self.options.print_legal_comment()
            && matches!(
                comment.content,
                CommentContent::Legal | CommentContent::JsdocLegal
            )
        {
            // Defer trailing legal comments until we find the next leading comment.
            pending_trailing_legal.push(*comment);
            continue;
        }

        if add {
            self.comments.entry(comment.attached_to).or_default().push(*comment);
        }
    }

    // Remaining trailing legal comments at the end of the file.
    // Attach to program end so they're printed by `print_comments_at(self.span.end)`.
    for mut tc in pending_trailing_legal {
        tc.attached_to = program_end;
        self.comments.entry(program_end).or_default().push(tc);
    }
}

